from models.base_task import BaseTask

class BugTask(BaseTask):
    def __init__(self, title, priority, severity):
        super().__init__(title, priority)
        self.severity = severity

    def summary(self):
        return f"BUG | {self.title} | priority: {self.priority} | severity: {self.severity}"

from models.base_task import BaseTask

class FeatureTask(BaseTask):
    def __init__(self, title, priority, feature_area):
        super().__init__(title, priority)
        self.feature_area = feature_area

    def summary(self):
        return f"FEATURE | {self.title} | priority: {self.priority} | feature: {self.feature_area}"

class TaskTracker:
    def __init__(self):
        self.tasks = []

    def add_task(self, task):
        self.tasks.append(task)

    def task_count(self):
        return len(self.tasks)

    def high_priority_titles(self):
        titles = []
        for task in self.tasks:
            if task.get_priority() == "high":
                titles.append(task.get_title())
        return titles

    def build_report(self):
        lines = ["SMART TASK TRACKER REPORT"]
        for task in self.tasks:
            lines.append(task.summary())
        return "\n".join(lines)

